use distributed_inference::loader::KnotWeights;
use distributed_inference::math::dequantize_q4k_row;

fn main() -> Result<(), String> {
    let knot = KnotWeights::load("/tmp/qwen-coder-7b.knot").map_err(|e| format!("{:?}", e))?;
    let bytes = knot
        .backend
        .fetch_tensor("token_embd_weight")
        .map_err(|e| format!("{:?}", e))?;
    let mut row = vec![0f32; 3584];
    dequantize_q4k_row(&mut row, &bytes, 576, 3584);
    println!("Rust:   row 576 (\" The\") first 8: {:?}", &row[..8]);
    let max = row.iter().fold(0f32, |a, &b| a.max(b.abs()));
    println!("Rust:   row 576 max_abs: {:.6}", max);
    Ok(())
}
